module reg_file(
   input                clk,
   input                rst_n,
   input                we,
   input      [2:0]     waddr,
   input      [31:0]    wdata,
   input      [2:0]     raddr1,
   input      [2:0]     raddr2,

   output     [31:0]    rdata1,
   output     [31:0]    rdata2
);
    reg [31:0] mem_reg [7:0];

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mem_reg[0] <= 32'd0;
            mem_reg[1] <= 32'd0;
            mem_reg[2] <= 32'd0;
            mem_reg[3] <= 32'd0;
            mem_reg[4] <= 32'd0;
            mem_reg[5] <= 32'd0;
            mem_reg[6] <= 32'd0;
            mem_reg[7] <= 32'd0;
        end
        else if (we) mem_reg[waddr] <= wdata;
    end

    assign rdata1 = mem_reg[raddr1];
    assign rdata2 = mem_reg[raddr2];
endmodule
